static inline float N99T_ftube(int t, float v){
  float x=(v-N99T_VMIN)*((N99T_N-1)/(N99T_VMAX-N99T_VMIN));
  if(x<=0)x=0; if(x>=N99T_N-1)x=N99T_N-1.001f;
  int i=(int)x; float fr=x-i; const float*T=(t?N99T_FT1:N99T_FT0);
  return T[i]+fr*(T[i+1]-T[i]);
}
static inline float N99T_ranode(int t, float v){
  float x=(v-N99T_VMIN)*((N99T_N-1)/(N99T_VMAX-N99T_VMIN));
  if(x<=0)x=0; if(x>=N99T_N-1)x=N99T_N-1.001f;
  int i=(int)x; float fr=x-i; const float*T=(t?N99T_RA1:N99T_RA0);
  return T[i]+fr*(T[i+1]-T[i]);
}
